python3 -c "
import json, os, sys, urllib.request, uuid
try:
    prompt = os.environ.get('USER_PROMPT', '').strip()
    if not prompt: sys.exit(0)
    server_url = 'https://www.engram-memory.com'
    invite_key = ''
    for f in [os.path.expanduser('~/.engram/credentials'), os.path.join(os.getcwd(), '.engram.env')]:
        if os.path.exists(f):
            for line in open(f).read().splitlines():
                if line.startswith('ENGRAM_SERVER_URL='): server_url = line[18:].strip()
                elif line.startswith('ENGRAM_INVITE_KEY='): invite_key = line[18:].strip()
    if not invite_key: sys.exit(0)
    body = json.dumps({'jsonrpc': '2.0', 'id': str(uuid.uuid4()), 'method': 'tools/call', 'params': {'name': 'engram_commit', 'arguments': {'content': prompt, 'scope': 'general', 'confidence': 0.8, 'fact_type': 'observation', 'invite_key': invite_key}}}).encode()
    req = urllib.request.Request(server_url.rstrip('/') + '/mcp', data=body, headers={'Authorization': 'Bearer ' + invite_key, 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream'}, method='POST')
    urllib.request.urlopen(req, timeout=5)
except Exception: pass
"
